import numpy as np, time
from scipy.linalg.lapack import dgeev
def bench(fn, sizes=range(2,11,2), N=2000):
    out=[]
    for s in sizes:
        dts=[]
        for _ in range(N):
            A=np.random.normal(size=(s,s)).astype(np.float64)
            t0=time.perf_counter(); fn(A); t1=time.perf_counter()
            dts.append(t1-t0)
        out.append(f"{s}:{np.median(dts)*1e6:.2f}us")
    print(" ".join(out))

def direct(A):
    wr,wi,vl,vr,info=dgeev(A,compute_vl=0,compute_vr=1)
    mag=wr*wr+wi*wi
    i=np.argmax(mag)
    if wi[i]==0:
        return complex(wr[i]), vr[:,i].astype(complex)
    # complex pair
    if wi[i]>0:
        vec=vr[:,i]+1j*vr[:,i+1]
    else:
        vec=vr[:,i-1]-1j*vr[:,i]
    return complex(wr[i],wi[i]), vec
print("direct dgeev"); bench(direct)
def ref(A):
    w,v=np.linalg.eig(A); i=np.argmax(np.abs(w)); return w[i],v[:,i]
print("eig"); bench(ref)
EOF
